CREATE OR REPLACE FUNCTION fpa_get_salary_id (as_memno char) RETURNS varchar AS $body$
DECLARE

  ls_salary_id sc_mem_m_member_work_info.salary_id%type;
  ls_member_name sc_mem_m_membership_registered.member_name%type;
  ls_memno sc_mem_m_membership_registered.membership_no%type;
  li_count integer;

  type tabi_memno is table of sc_mem_m_membership_registered.membership_no%type index by integer;
  cur_member CURSOR FOR
  SELECT membership_no,member_name
  from sc_mem_m_membership_registered
  where (member_status_code = '0');
  type tabrowi_member is table of cur_member%rowtype index by integer;
  ltabi_memno tabi_memno;
  ltabrowi_member tabrowi_member;
BEGIN
  select membership_no bulk collect into STRICT ltabi_memno
  from sc_mem_m_membership_registered
  where (member_status_code = '0');
  li_count := ltabi_memno.count;
  for i in 1..li_count loop
    ls_memno := ltabi_memno(i);
  end loop;

  open cur_member;
  fetch cur_member bulk collect into ltabrowi_member;
  close cur_member;
  li_count := ltabrowi_member.count;
  for i in 1..li_count loop
    ls_memno := ltabrowi_member[i].membership_no;
    ls_member_name := ltabrowi_member[i].member_name;
  end loop;

  return null;
exception  when others then CALL spa_dberror('fpa_get_salary_id('||trim(both as_memno)||')');
end;
